if (!output || typeof output !== "string") {
        return { pass: false, score: 0, reason: "Output is empty or not a string" };
    }

    try {
        JSON.parse(output);
        return { pass: true, score: 1, reason: "Valid JSON" };
    } catch (err) {

        const preview = output.slice(0, 200).replace(/\n/g, "\\n");
        return {
            pass: false,
            score: 0,
            reason: `Response is not valid JSON: ${err.message}. Preview: "${preview}"`,
        };
    }

let parsed;
    try {
        parsed = JSON.parse(output);
    } catch {
        return { pass: false, score: 0, reason: "Not valid JSON — cannot check required fields" };
    }

    const errors = [];


    if (!("actions" in parsed)) {
        errors.push("missing field: actions");
    } else if (!Array.isArray(parsed.actions)) {
        errors.push(`actions must be an array, got ${typeof parsed.actions}`);
    }


    if (!("thread_updates" in parsed)) {
        errors.push("missing field: thread_updates");
    } else if (parsed.thread_updates !== null && !Array.isArray(parsed.thread_updates)) {
        errors.push(`thread_updates must be an array or null, got ${typeof parsed.thread_updates}`);
    }


    const triggerType = context?.vars?.trigger_type ?? "email_received";
    if (triggerType === "email_received") {
        if (!("email_analysis" in parsed)) {
            errors.push("missing field: email_analysis (required for email_received trigger)");
        } else if (parsed.email_analysis !== null && typeof parsed.email_analysis !== "object") {
            errors.push(`email_analysis must be an object or null, got ${typeof parsed.email_analysis}`);
        }


        if (parsed.email_analysis && typeof parsed.email_analysis === "object") {
            const analysis = parsed.email_analysis;
            const requiredAnalysisFields = ["summary", "intent", "urgency", "entities"];
            const missingAnalysis = requiredAnalysisFields.filter(f => !(f in analysis));
            if (missingAnalysis.length > 0) {
                errors.push(`email_analysis missing fields: ${missingAnalysis.join(", ")}`);
            }

            const validUrgencies = ["low", "normal", "high"];
            if (analysis.urgency && !validUrgencies.includes(analysis.urgency)) {
                errors.push(`email_analysis.urgency must be low|normal|high, got "${analysis.urgency}"`);
            }

            if ("entities" in analysis && !Array.isArray(analysis.entities)) {
                errors.push(`email_analysis.entities must be an array, got ${typeof analysis.entities}`);
            }
        }
    }


    if (Array.isArray(parsed.actions)) {
        for (let i = 0; i < parsed.actions.length; i++) {
            const action = parsed.actions[i];
            if (!action.tool) errors.push(`actions[${i}] missing tool`);
            if (!action.params || typeof action.params !== "object") {
                errors.push(`actions[${i}] missing or invalid params`);
            }
        }
    }

    if (errors.length > 0) {
        return { pass: false, score: 0, reason: errors.join("; ") };
    }

    return { pass: true, score: 1, reason: "All required fields present" };

let parsed;
    try {
        parsed = JSON.parse(output);
    } catch {
        return { pass: false, score: 0, reason: "Not valid JSON" };
    }

    const analysis = parsed.email_analysis;
    if (!analysis) {

        const triggerType = context?.vars?.trigger_type ?? "email_received";
        if (triggerType !== "email_received") return { pass: true, score: 1, reason: "Not an email trigger" };
        return { pass: false, score: 0, reason: "email_analysis missing on email_received trigger" };
    }

    const urgency = analysis.urgency;
    const emailType = (context?.vars?.email_type ?? "").toLowerCase();
    const expectedUrgency = context?.vars?.expected_urgency;

    const validUrgencies = ["low", "normal", "high"];
    if (!validUrgencies.includes(urgency)) {
        return { pass: false, score: 0, reason: `Invalid urgency value: "${urgency}". Must be low|normal|high` };
    }


    const neverHighTypes = ["receipt", "confirmation", "newsletter", "shipping", "spam", "account_setup"];
    if (neverHighTypes.includes(emailType) && urgency === "high") {
        return {
            pass: false,
            score: 0,
            reason: `${emailType} emails must not be high urgency (got: high). The system prompt says confirmations and receipts are expected events.`,
        };
    }


    if (emailType === "security_alert" && urgency === "low") {
        return {
            pass: false,
            score: 0,
            reason: `security_alert must not be low urgency. Security events should be normal or high.`,
        };
    }


    if (emailType === "action_request" && urgency === "low") {
        return {
            pass: false,
            score: 0,
            reason: `action_request emails must not be low urgency. Someone is waiting for a response.`,
        };
    }

    if (emailType === "deadline" && urgency === "low") {
        return {
            pass: false,
            score: 0,
            reason: `deadline emails must not be low urgency. Deadlines within 48 hours require attention.`,
        };
    }


    if (expectedUrgency && urgency !== expectedUrgency) {
        return {
            pass: false,
            score: 0.5,
            reason: `Expected urgency "${expectedUrgency}" but got "${urgency}" for ${emailType} email`,
        };
    }

    return { pass: true, score: 1, reason: "Urgency check passed" };

let parsed;
    try {
        parsed = JSON.parse(output);
    } catch {
        return { pass: false, score: 0, reason: "Not valid JSON" };
    }

    const actions = parsed.actions ?? [];
    const alertActions = actions.filter(a => a.tool === "send_alert");
    const hasAlert = alertActions.length > 0;

    const emailType = (context?.vars?.email_type ?? "").toLowerCase();
    const shouldAlert = context?.vars?.should_alert;


    const noAlertTypes = ["receipt", "newsletter", "spam", "shipping", "confirmation", "account_setup"];

    if (noAlertTypes.includes(emailType) && hasAlert) {
        const alertMessages = alertActions.map(a =>
            `tool=${a.tool} message="${String(a.params?.message ?? "").slice(0, 80)}"`
        ).join("; ");
        return {
            pass: false,
            score: 0,
            reason: `${emailType} emails must not trigger send_alert. Got: [${alertMessages}]`,
        };
    }


    if (shouldAlert === false && hasAlert) {
        const alertMessages = alertActions.map(a =>
            `"${String(a.params?.message ?? "").slice(0, 80)}"`
        ).join("; ");
        return {
            pass: false,
            score: 0,
            reason: `Test expects no alert, but send_alert was triggered: ${alertMessages}`,
        };
    }



    if (shouldAlert === true && !hasAlert) {
        return {
            pass: false,
            score: 0.4,
            reason: `Test expects an alert (should_alert=true) but no send_alert action was found. Other actions: ${JSON.stringify(actions.map(a => a.tool))}`,
        };
    }


    if (emailType === "tick" && hasAlert) {
        const shouldAlertOnTick = context?.vars?.should_alert;
        if (shouldAlertOnTick === false) {
            return {
                pass: false,
                score: 0,
                reason: `Tick test expects no alert but send_alert was fired. Only overdue active threads should trigger silence alerts.`,
            };
        }
    }

    return { pass: true, score: 1, reason: "Alert check passed" };

let parsed;
    try { parsed = JSON.parse(output); }
    catch { return { pass: false, score: 0, reason: "Not valid JSON" }; }

    const norm = (s) => s.replace(/\s+/g, " ").trim().toLowerCase();
    const emailBody = norm(context?.vars?.email_body ?? "");
    const memories = parsed.memory_append;

    if (!memories || (Array.isArray(memories) && memories.length === 0))
        return { pass: true, score: 1, reason: "No memories to validate" };

    const memArray = Array.isArray(memories) ? memories : [memories];
    const errors = [];

    const isGrounded = (quote, body) => {
        const words = norm(quote).split(" ").filter(w => w.length > 1);
        if (words.length <= 5) return body.includes(norm(quote));
        const W = 5;
        let hits = 0, total = 0;
        for (let i = 0; i <= words.length - W; i++) {
            const ngram = words.slice(i, i + W).join(" ");
            if (body.includes(ngram)) hits++;
            total++;
        }
        return total === 0 || (hits / total) >= 0.5;
    };

    for (const mem of memArray) {
        if (!mem || typeof mem !== "object") continue;
        const importance = mem.importance ?? 3;
        const quote = mem.source_quote;

        if (importance >= 4 && !quote) {
            errors.push(`importance=${importance} memory missing source_quote: "${String(mem.content ?? "").slice(0, 80)}"`);
            continue;
        }

        if (quote && typeof quote === "string" && emailBody) {
            if (!isGrounded(quote, emailBody))
                errors.push(`Hallucinated quote not grounded in email: "${quote.slice(0, 100)}"`);
        }
    }

    if (errors.length > 0)
        return { pass: false, score: 0, reason: errors.join("; ") };

    return { pass: true, score: 1, reason: "All quotes verified" };

let parsed;
    try {
        parsed = JSON.parse(output);
    } catch {
        return { pass: false, score: 0, reason: "Not valid JSON" };
    }

    const memories = parsed.memory_append;
    const emailType = (context?.vars?.email_type ?? "").toLowerCase();

    const noMemoryTypes = ["spam", "newsletter", "account_setup", "confirmation", "shipping"];
    const highImportanceAllowed = ["action_request", "deadline", "security_alert", "financial", "meeting_request", "question"];

    if (!memories || (Array.isArray(memories) && memories.length === 0)) {
        return { pass: true, score: 1, reason: "No memories stored" };
    }

    const memArray = Array.isArray(memories) ? memories : [memories];

    if (noMemoryTypes.includes(emailType) && memArray.length > 0) {
        return {
            pass: false,
            score: 0,
            reason: `Should not store memories for '${emailType}' emails. Stored ${memArray.length} memory(ies): ${memArray.map(m => `"${String(m.content ?? "").slice(0, 60)}"`).join(", ")}`,
        };
    }

    if (memArray.length > 3) {
        return {
            pass: false,
            score: 0.3,
            reason: `Too many memories: ${memArray.length} (max 3 per email).`,
        };
    }

    const importances = memArray.map(m => {
        const imp = Number(m.importance);
        return isNaN(imp) ? 3 : Math.max(1, Math.min(5, imp));
    }).sort((a, b) => a - b);


    const has5 = importances.some(i => i === 5);
    if (has5 && !highImportanceAllowed.includes(emailType)) {
        return {
            pass: false,
            score: 0.5,
            reason: `Memory importance 5 is too high for '${emailType}' emails. Importances: [${importances.join(", ")}]`,
        };
    }


    if (memArray.length >= 2) {
        const mid = Math.floor(importances.length / 2);
        const median = importances.length % 2 === 0
            ? ((importances[mid - 1] ?? 3) + (importances[mid] ?? 3)) / 2
            : (importances[mid] ?? 3);

        if (median > 4) {
            return {
                pass: false,
                score: 0.5,
                reason: `Memory importance median too high: ${median} (should be ≤ 4 when storing multiple). Importances: [${importances.join(", ")}].`,
            };
        }
    }

    return { pass: true, score: 1, reason: "Memory check passed" };

